export class MovePlugin {
  id = "move";
  #pluginManager;
  constructor(pluginManager) {
    this.#pluginManager = pluginManager;
  }
  async getPlugin(container) {
    const {
      MovePluginInstance
    } = await import("./MovePluginInstance.js");
    return new MovePluginInstance(this.#pluginManager, container);
  }
  loadOptions() {}
  needsPlugin() {
    return true;
  }
}