import { PolygonDrawerBase } from "./PolygonDrawerBase.js";
const sides = 3,
  yFactor = 2.66,
  sidesFactor = 3;
export class TriangleDrawer extends PolygonDrawerBase {
  getSidesCount() {
    return sides;
  }
  getSidesData(_particle, radius) {
    return {
      count: {
        denominator: 1,
        numerator: sides
      },
      length: radius * yFactor / (sides / sidesFactor)
    };
  }
}