import { PolygonDrawerBase } from "./PolygonDrawerBase.js";
const yFactor = 2.66,
  sidesFactor = 3;
export class PolygonDrawer extends PolygonDrawerBase {
  getSidesData(particle, radius) {
    const {
      sides
    } = particle;
    return {
      count: {
        denominator: 1,
        numerator: sides
      },
      length: radius * yFactor / (sides / sidesFactor)
    };
  }
}