export class LinksPlugin {
  id = "links";
  #pluginManager;
  constructor(pluginManager) {
    this.#pluginManager = pluginManager;
  }
  async getPlugin(container) {
    const {
      LinkInstance
    } = await import("./LinkInstance.js");
    return new LinkInstance(this.#pluginManager, container);
  }
  loadOptions() {}
  needsPlugin() {
    return true;
  }
}